class _UniffiFfiConverterTypeMmexEngine:
    @staticmethod
    def lift(value: int) -> MmexEngine:
        return MmexEngine._uniffi_make_instance(value)

    @staticmethod
    def check_lower(value: MmexEngine):
        if not isinstance(value, MmexEngine):
            raise TypeError("Expected MmexEngine instance, {} found".format(type(value).__name__))

    @staticmethod
    def lower(value: MmexEngine) -> ctypes.c_uint64:
        return value._uniffi_clone_handle()

    @classmethod
    def read(cls, buf: _UniffiRustBuffer) -> MmexEngine:
        ptr = buf.read_u64()
        if ptr == 0:
            raise InternalError("Raw handle value was null")
        return cls.lift(ptr)

    @classmethod
    def write(cls, value: MmexEngine, buf: _UniffiRustBuffer):
        buf.write_u64(cls.lower(value))

